function Parallax({ scrollPercentage, layers }) {
    return (
      <div className="Parallax">
        {layers.map((layer, index) => {
          console.log(`Layer ${index + 1} - scrollPercentage: ${scrollPercentage}, speed: ${layer.speed}`);
          return (
            <div
              key={index}
              className={`Layer${index + 1}`}
              style={{
                backgroundImage: `url('${layer.image}')`,
                backgroundPositionX: `calc(${scrollPercentage * layer.speed}% ${layer.offset})`
              }}
            ></div>
          );
        })}
      </div>
    );
  }
